figure('Units','inches','Position',[1,1,6.5,4]); %[output:05f46b22]
hold on; %[output:05f46b22]

cost_k = [heuristic_k; greedy_k; optimised_k];   % 3-by-3 (in k€)
b = bar(x, cost_k', bar_width); %[output:05f46b22]

% Colors
b(1).FaceColor = [0.30 0.55 0.85];   % Blue  – Heuristic %[output:05f46b22]
