ylabel('Cost (thousand euros)');  % <-- scaled axis %[output:05f46b22]
set(gca, 'XTick', x, 'XTickLabel', labels); %[output:05f46b22]

legend('Heuristic', 'Global Greedy', 'Recruitment and Allocation Model', ... %[output:05f46b22]
       'Location', 'northwest'); %[output:05f46b22]

ylim([0, max(cost_k(:)) * 1.15]); %[output:05f46b22]
set(gca, 'FontName', 'Arial', 'FontSize', 10); %[output:05f46b22]
