    values = cost_k(i, :);
    for j = 1:numel(x_endpoints)
        % show with 1 decimal place to avoid crowding (e.g., 581.8)
        text(x_endpoints(j), y_endpoints(j) + yoff, sprintf('%.1f', values(j)), ... %[output:05f46b22]
            'HorizontalAlignment', 'center', 'VerticalAlignment', 'bottom', 'FontSize', 10); %[output:05f46b22]
    end
end
fprintf('%s%d', 'Total number of recruited patients: ', round(sum(y_opt))); %[output:8999b025]

set(gcf, 'PaperPositionMode', 'auto');
exportgraphics(gcf, fullfile(graphicFolder, 'metabolomic_cost_opt_vs_heu_vs_greedy.png'), 'Resolution', 600); %[output:05f46b22]
